sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var body = request.body.data;

    if (!body.requirement) {
        response.setStatus(400);
        response.setError('Requirement is required');
        return;
    }

    var options = {
        qualityWeight: body.qualityWeight || 0.5,
        tokenCostWeight: body.tokenCostWeight || 0.3,
        speedWeight: body.speedWeight || 0.2
    };

    var selector = new x_146833_idpkiro.BuildAgentSelector();
    var result = selector.selectAgent(body.requirement, options);

    if (result.error) {
        response.setStatus(400);
        response.setError(result.error);
        return;
    }

    // Build comparison matrix
    var comparison = result.allScores.map(function(s) {
        return {
            name: s.name,
            totalScore: s.score.toFixed(4),
            breakdown: {
                quality: (s.breakdown.quality * 100).toFixed(1) + '%',
                cost: (s.breakdown.cost * 100).toFixed(1) + '%',
                speed: (s.breakdown.speed * 100).toFixed(1) + '%',
                specializationBonus: s.breakdown.specializationBonus > 0 ? 'Yes (+20%)' : 'No'
            }
        };
    });

    response.setStatus(200);
    response.setBody({
        success: true,
        taskType: result.selectedAgent ? 'detected' : 'general',
        recommendation: {
            agent: result.selectedAgent.name,
            score: result.score.toFixed(4),
            reasoning: result.reasoning
        },
        comparison: comparison
    });
})(request, response);
